def g(d, prefix, raw):
    def fa(ans):
        if isinstance(ans, list): return ans
        return [ord(c)-65 for c in ans.upper()]

    def ft(t): return "single" if t == 1 else "multiple"
    def fd(diff): return ["easy", "medium", "hard"][diff-1]

    return [{"id": f"{prefix}_{i+1:03d}","domain": d,"type": ft(r[0]),"question": r[1],"options": r[2],"answer": fa(r[3]),"difficulty": fd(r[4]),"explanation": r[5],"tags": r[6]} for i, r in enumerate(raw)]

